// ─── Habibbo ───

function Habibbo() {
  const [ref, visible] = useReveal(0.1);
  const [currentImg, setCurrentImg] = useState(0);
  const scrollRef = useRef(null);

  const nextImg = () => setCurrentImg((p) => (p + 1) % habibboImages.length);
  const prevImg = () => setCurrentImg((p) => (p - 1 + habibboImages.length) % habibboImages.length);

  useEffect(() => {
    const timer = setInterval(nextImg, 4000);
    return () => clearInterval(timer);
  }, []);

  return (
    <>
      <style>{`
        .habibbo {
          padding: clamp(80px, 10vw, 160px) clamp(24px, 5vw, 80px);
          background: var(--bg-alt); position: relative; overflow: hidden;
        }
        .habibbo-inner { max-width: 1200px; margin: 0 auto; }
        .habibbo-grid {
          display: grid; grid-template-columns: 1fr 1fr; gap: 60px; align-items: center;
        }
        .habibbo-gallery {
          position: relative; border-radius: 20px; overflow: hidden;
          aspect-ratio: 3/2;
          box-shadow: 0 8px 40px rgba(0,0,0,0.1);
        }
        .habibbo-slide {
          position: absolute; inset: 0; opacity: 0;
          transition: opacity 0.8s cubic-bezier(.22,1,.36,1);
        }
        .habibbo-slide.active { opacity: 1; }
        .habibbo-slide img {
          width: 100%; height: 100%; object-fit: cover;
        }
        .habibbo-dots {
          display: flex; gap: 8px; margin-top: 16px; justify-content: center;
        }
        .habibbo-dot {
          width: 8px; height: 8px; border-radius: 50%;
          background: var(--border); border: none; cursor: pointer;
          transition: all 0.3s; padding: 0;
        }
        .habibbo-dot.active { background: var(--text); transform: scale(1.3); }
        .habibbo-nav {
          position: absolute; top: 50%; transform: translateY(-50%);
          width: 36px; height: 36px; border-radius: 50%;
          background: var(--nav-bg); backdrop-filter: blur(10px);
          border: none; cursor: pointer; display: flex;
          align-items: center; justify-content: center; z-index: 2;
          opacity: 0; transition: opacity 0.3s;
        }
        .habibbo-gallery:hover .habibbo-nav { opacity: 1; }
        .habibbo-nav.prev { left: 12px; }
        .habibbo-nav.next { right: 12px; }
        .habibbo-text h3 {
          font-family: 'SF Pro Display', -apple-system, sans-serif;
          font-size: clamp(28px, 3.5vw, 40px); font-weight: 600;
          letter-spacing: -0.03em; color: var(--text); margin: 0 0 8px;
        }
        .habibbo-text .hab-origin {
          font-family: 'SF Mono', 'Fira Code', monospace;
          font-size: 13px; color: var(--text-muted); margin-bottom: 24px;
          display: block;
        }
        .habibbo-text p {
          font-family: 'SF Pro Text', -apple-system, sans-serif;
          font-size: 15px; line-height: 1.7; color: var(--text-soft); margin: 0 0 16px;
        }
        .habibbo-text .hab-highlight {
          font-family: 'SF Pro Text', -apple-system, sans-serif;
          font-size: 15px; line-height: 1.7; color: var(--text);
          font-weight: 500;
        }
        @media (max-width: 768px) {
          .habibbo-grid { grid-template-columns: 1fr; gap: 40px; }
        }
      `}</style>

      <section className="habibbo" ref={ref}>
        <div className="habibbo-inner">
          <div className="slbl">Projeto Pessoal</div>
          <div className="habibbo-grid" style={{
            opacity: visible ? 1 : 0, transform: visible ? "translateY(0)" : "translateY(32px)",
            transition: "all 0.8s cubic-bezier(.22,1,.36,1)",
          }}>
            <div>
              <div className="habibbo-gallery">
                {habibboImages.map((img, i) => (
                  <div key={i} className={`habibbo-slide ${i === currentImg ? "active" : ""}`}>
                    <img src={img} alt={`Habibbo ${i + 1}`} />
                  </div>
                ))}
                <button className="habibbo-nav prev" onClick={prevImg}>
                  <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="var(--text)" strokeWidth="2" strokeLinecap="round"><path d="M15 18l-6-6 6-6"/></svg>
                </button>
                <button className="habibbo-nav next" onClick={nextImg}>
                  <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="var(--text)" strokeWidth="2" strokeLinecap="round"><path d="M9 18l6-6-6-6"/></svg>
                </button>
              </div>
              <div className="habibbo-dots">
                {habibboImages.map((_, i) => (
                  <button key={i} className={`habibbo-dot ${i === currentImg ? "active" : ""}`} onClick={() => setCurrentImg(i)} />
                ))}
              </div>
            </div>

            <div className="habibbo-text">
              <h3>Habibbo</h3>
              <span className="hab-origin">Do árabe حبيب (Habib) — "querido", "amado"</span>

              <p>A Habibbo nasceu de uma experiência que mudou tudo. Durante uma viagem ao Oriente Médio, participamos de iniciativas humanitárias voltadas ao apoio de refugiados da guerra, servindo comunidades locais no Líbano e no Egito.</p>

              <p>Ao longo desse período, tivemos a oportunidade de contribuir com diferentes frentes de ajuda em campos de refugiados, orfanatos, escolas e universidades, alcançando mais de 3.000 pessoas.</p>

              <p>Hoje, a Habibbo se tornou o braço de desenvolvimento tecnológico que conecta propósito com criação. Construímos soluções digitais e sistemas full stack para criadores, empresas e projetos que precisam transformar ideias em realidade rapidamente.</p>

              <p className="hab-highlight">Mais do que tecnologia, acreditamos em construir ferramentas que sirvam pessoas e ampliem impacto. Porque boas ideias merecem ganhar forma.</p>
            </div>
          </div>
        </div>
      </section>
    </>
  );
}

